sql:
SELECT actor_name
FROM actors
WHERE actor_id > 0;

SELECT COUNT(*) AS unique_awards_won
FROM (
  SELECT awards_won FROM actors
  UNION
  SELECT awards_won FROM directors
) AS combined_awards;

SELECT a.actor_name
FROM actors a
INNER JOIN directors d ON a.actor_name = d.director_name;

SELECT 
  (SELECT AVG(actor_facebook_likes) FROM actors WHERE filmography LIKE '%Film 1%') AS average_actor_facebook_likes,
  (SELECT AVG(director_facebook_likes) FROM directors WHERE filmography LIKE '%Film 1%') AS average_director_facebook_likes;

SELECT 
  (SELECT AVG(actor_facebook_likes) FROM actors) AS avg_actor_likes,
  (SELECT AVG(director_facebook_likes) FROM directors) AS avg_director_likes;

external_knowledge:
- "stars" refers to actors;
- "crowned with accolades" refers to winning awards;
- "the vast theater of cinema" refers to the film industry.

- 'decorated pairs' refers to actors and directors who have won or been nominated for awards;
- 'lineage of their representatives' refers to the hierarchical structure of actors and directors, where each can have a representative or agent;
- 'combined glory' refers to the sum of awards won and nominations for both the actor and director in a pair;
- 'top 10' refers to the limitation of the result to the 10 highest-ranking pairs.

- "Facebook likes" can be a measure of popularity or influence on social media;
- "nationality" refers to the country of origin or citizenship of the actors and directors;
- The query excludes nationalities with only one actor or one director to focus on more diverse or representative groups.

sql:
SELECT AVG(facebook_likes) AS average_facebook_likes
FROM (
    SELECT actor_facebook_likes AS facebook_likes FROM actors
    UNION ALL
    SELECT director_facebook_likes AS facebook_likes FROM directors
) AS combined_likes;

SELECT a.actor_name, d.director_name
FROM actors a
LEFT JOIN directors d ON a.actor_id = d.director_id;
